import{_ as t,C as a,o as l,c as s,ai as r,E as i}from"./chunks/framework.BIXs0jTs.js";const n="/assets/preface-cover.Balx8Fq4.png",m=JSON.parse('{"title":"MCP 概念与设计思想","description":"","frontmatter":{"title":"MCP 概念与设计思想"},"headers":[],"relativePath":"30-mcp/intro.md","filePath":"30-mcp/intro.md","lastUpdated":null}'),d={name:"30-mcp/intro.md"};function u(c,e,p,h,C,P){const o=a("Mermaid");return l(),s("div",null,[e[0]||(e[0]=r('<h1 id="第-8-章-mcp-概念与设计思想-连接-ai-与世界的通用协议" tabindex="-1">第 8 章　MCP 概念与设计思想：连接 AI 与世界的通用协议 <a class="header-anchor" href="#第-8-章-mcp-概念与设计思想-连接-ai-与世界的通用协议" aria-label="Permalink to &quot;第 8 章　MCP 概念与设计思想：连接 AI 与世界的通用协议&quot;">​</a></h1><p><img src="'+n+'" alt="MCP 概念与设计思想：连接 AI 与世界的通用协议"></p><p>在前面的章节中，我们把 Claude Code 当作一个“只懂代码”的助手：它能读文件、写文件、跑终端。这对于写代码来说已经很棒了。 但是，<strong>真实世界的数据并不都躺在文件系统里</strong>。</p><p>你的 Bug 单在 Jira 上，你的监控数据在 Prometheus 里，你的用户数据在 PostgreSQL 数据库中，你的部署状态在 Kubernetes 集群里。如果 Claude Code 只能读本地文件，那它就只是一个“跛脚”的工程师——每次都要你手动去查这些系统，然后复制粘贴给它。</p><p><strong>MCP (Model Context Protocol)</strong> 就是为了解决这个问题而诞生的。它是一套开放标准，旨在让 AI 模型能够以安全、统一的方式连接到任何外部数据源和工具。</p><h2 id="_8-1-什么是-mcp" tabindex="-1">8.1 什么是 MCP？ <a class="header-anchor" href="#_8-1-什么是-mcp" aria-label="Permalink to &quot;8.1 什么是 MCP？&quot;">​</a></h2><p>用一句话解释：<strong>MCP 是 AI 时代的 USB 协议。</strong></p><p>在过去，如果你想让 AI 连接数据库，你得写一段特定的代码；想连接 Slack，又得写另一段代码。这就像以前买鼠标要分 PS/2 接口、串口接口一样麻烦。 MCP 定义了一套通用的接口标准（Client-Host-Server），只要你的工具（如 Linear、GitHub、Postgres）实现了一个 MCP Server，任何支持 MCP 的 AI 客户端（如 Claude Code、Cursor、Zed）就都能直接使用它，而无需专门适配。</p><h3 id="_8-1-1-核心架构" tabindex="-1">8.1.1 核心架构 <a class="header-anchor" href="#_8-1-1-核心架构" aria-label="Permalink to &quot;8.1.1 核心架构&quot;">​</a></h3><p>MCP 体系包含三个角色：</p><ol><li><p><strong>MCP Host (宿主)</strong>：发起请求的一方。</p><ul><li>在本书的语境下，<strong>Claude Code 就是 Host</strong>。它负责把用户的自然语言需求转化为对 MCP 工具的调用。</li></ul></li><li><p><strong>MCP Server (服务端)</strong>：提供能力的一方。</p><ul><li>这是一个轻量级的服务，它不直接与用户对话，而是暴露两类东西： <ul><li><strong>Resources (资源)</strong>：类似文件的数据（如“今天的服务器日志”、“用户表的前10行”）。</li><li><strong>Tools (工具)</strong>：可执行的函数（如“创建一个 Jira Ticket”、“重启 Pod”）。</li></ul></li></ul></li><li><p><strong>MCP Client (客户端)</strong>：</p><ul><li>连接 Host 和 Server 的桥梁（在 Claude Code 内部已内置）。</li></ul></li></ol>',11)),i(o,{id:"mermaid_382ee21e",graph:"flowchart%20LR%0A%20%20%20%20User%5B%22%E7%94%A8%E6%88%B7%22%5D%20--%20%22%E5%B8%AE%E6%88%91%E6%9F%A5%E4%B8%8B%E6%95%B0%E6%8D%AE%E5%BA%93%22%20--%3E%20Host%5B%22Claude%20Code%20(Host)%22%5D%0A%20%20%20%20Host%20--%20%22MCP%20Protocol%22%20--%3E%20Server%5B%22SQLite%20MCP%20Server%22%5D%0A%20%20%20%20Server%20--%20%22SQL%20Query%22%20--%3E%20DB%5B(%22%E6%9C%AC%E5%9C%B0%20SQLite%22)%5D%0A%20%20%20%20Server%20--%20%22Result%22%20--%3E%20Host%0A%20%20%20%20Host%20--%20%22%E8%87%AA%E7%84%B6%E8%AF%AD%E8%A8%80%E5%9B%9E%E7%AD%94%22%20--%3E%20User"}),e[1]||(e[1]=r('<hr><h2 id="_8-2-为什么-mcp-比-写个脚本-更好" tabindex="-1">8.2 为什么 MCP 比“写个脚本”更好？ <a class="header-anchor" href="#_8-2-为什么-mcp-比-写个脚本-更好" aria-label="Permalink to &quot;8.2 为什么 MCP 比“写个脚本”更好？&quot;">​</a></h2><p>你可能会问：“如果我要查数据库，我直接让 Claude 写个 Python 脚本跑一下不就行了？为什么要搞这么复杂的协议？”</p><h3 id="_8-2-1-安全性-security" tabindex="-1">8.2.1 安全性 (Security) <a class="header-anchor" href="#_8-2-1-安全性-security" aria-label="Permalink to &quot;8.2.1 安全性 (Security)&quot;">​</a></h3><ul><li><strong>脚本</strong>：Claude 生成的脚本可能包含 <code>rm -rf</code> 或者把密钥打印出来。你每次运行都要心惊胆战地 Review。</li><li><strong>MCP</strong>：Server 是你预先部署好的，逻辑是固定的。你只暴露了 <code>query_users</code> 接口，Claude 就绝对无法执行 <code>drop_table</code>（除非你故意暴露了这个功能）。<strong>权限控制在开发者手中，而不是 AI 手中。</strong></li></ul><h3 id="_8-2-2-上下文保持-context" tabindex="-1">8.2.2 上下文保持 (Context) <a class="header-anchor" href="#_8-2-2-上下文保持-context" aria-label="Permalink to &quot;8.2.2 上下文保持 (Context)&quot;">​</a></h3><ul><li><strong>脚本</strong>：是一次性的。跑完就没了，下一次对话又要重新生成。</li><li><strong>MCP</strong>：Server 是常驻的。Claude 可以持续通过 <code>Resources</code> 订阅数据变化。例如，你可以让 Claude 监控日志文件的尾部，一旦出现 Error 就报警。</li></ul><h3 id="_8-2-3-复用性-reusability" tabindex="-1">8.2.3 复用性 (Reusability) <a class="header-anchor" href="#_8-2-3-复用性-reusability" aria-label="Permalink to &quot;8.2.3 复用性 (Reusability)&quot;">​</a></h3><ul><li><strong>脚本</strong>：通常只针对当前问题。</li><li><strong>MCP</strong>：一旦你写好了 <code>Jira MCP Server</code>，全团队的人、所有的 AI 客户端（不仅是 Claude Code）都可以直接复用。</li></ul><hr><h2 id="_8-3-mcp-的三大支柱-resources-prompts-tools" tabindex="-1">8.3 MCP 的三大支柱：Resources, Prompts, Tools <a class="header-anchor" href="#_8-3-mcp-的三大支柱-resources-prompts-tools" aria-label="Permalink to &quot;8.3 MCP 的三大支柱：Resources, Prompts, Tools&quot;">​</a></h2><p>在开发 MCP Server 时，你需要关注这三个核心概念：</p><h3 id="_8-3-1-resources-资源" tabindex="-1">8.3.1 Resources (资源) <a class="header-anchor" href="#_8-3-1-resources-资源" aria-label="Permalink to &quot;8.3.1 Resources (资源)&quot;">​</a></h3><p><strong>“给 AI 看的数据。”</strong> 资源是只读的。它们可以是文件、数据库记录、API 返回的 JSON。</p><ul><li>例子：<code>postgres://users/123</code></li><li>AI 行为：<code>read_resource(uri)</code></li></ul><h3 id="_8-3-2-tools-工具" tabindex="-1">8.3.2 Tools (工具) <a class="header-anchor" href="#_8-3-2-tools-工具" aria-label="Permalink to &quot;8.3.2 Tools (工具)&quot;">​</a></h3><p><strong>“让 AI 做的事情。”</strong> 工具是可执行的函数，通常会有副作用（修改数据）。</p><ul><li>例子：<code>create_issue(title, description)</code></li><li>AI 行为：<code>call_tool(name, arguments)</code></li></ul><h3 id="_8-3-3-prompts-提示词模板" tabindex="-1">8.3.3 Prompts (提示词模板) <a class="header-anchor" href="#_8-3-3-prompts-提示词模板" aria-label="Permalink to &quot;8.3.3 Prompts (提示词模板)&quot;">​</a></h3><p><strong>“教 AI 怎么用。”</strong> Server 可以内置一些 Prompt 模板，告诉 Host 如何更好地使用自己提供的资源和工具。</p><ul><li>例子：<code>explain-query-plan</code>（当用户问查询性能时，自动调用此模板）。</li></ul><hr><h2 id="_8-4-小结" tabindex="-1">8.4 小结 <a class="header-anchor" href="#_8-4-小结" aria-label="Permalink to &quot;8.4 小结&quot;">​</a></h2><p>MCP 不是什么黑科技，它只是把“AI 调用外部工具”这件事标准化了。</p><ul><li>它让 AI 从“文件系统的囚徒”变成了“数字世界的游侠”。</li><li>它通过标准协议解决了安全性、复用性和上下文问题。</li></ul><p>在下一章，我们将不动嘴皮子，直接动手写代码——<strong>从零开发你的第一个 MCP Server</strong>。无论你是用 Python 还是 TypeScript，只要 10 分钟，你就能让 Claude Code 拥有“超能力”。</p>',26))])}const g=t(d,[["render",u]]);export{m as __pageData,g as default};
